            font-size: 13px;
        }
        .cell:focus {
            background-color: #e8f0fe;
            box-shadow: inset 0 0 2px 1px rgba(66, 153, 225, 0.7);
        }
        .error {
            color: red;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="toolbar">
            <button id="export">Export CSV</button>
            <textarea id="csv" readonly placeholder="CSV output will appear here..."></textarea>
        </div>
        <div class="spreadsheet" id="grid-container">
            <!-- Grid will be generated by JavaScript -->
        </div>
    </div>

    <script>
        // Spreadsheet implementation
        const ROWS = 10;
        const COLS = 10;
        const COLS_LABELS = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];

        // Store raw cell values and computed values
        const rawData = {};
        const computedValues = {};
        const dependencies = {}; // Map from cell to cells that depend on it

        // Initialize data structures
        for (let r = 1; r <= ROWS; r++) {
            for (let c = 0; c < COLS; c++) {
                const cellId = `cell-${COLS_LABELS[c]}${r}`;
                rawData[cellId] = '';
                computedValues[cellId] = '';
                dependencies[cellId] = new Set();
            }
        }

        // Tokenize and parse formula
        function tokenize(formula) {
            const tokens = [];
            let i = 0;

            while (i < formula.length) {
                const ch = formula[i];

                if (ch === ' ') {
                    i++;
                    continue;
                }

                if ('+-*/()'.includes(ch)) {
                    tokens.push({ type: 'op', value: ch });
                    i++;
                } else if (ch >= '0' && ch <= '9') {
                    let numStr = '';
                    while (i < formula.length && (formula[i] >= '0' && formula[i] <= '9')) {
                        numStr += formula[i];
                        i++;
                    }
                    tokens.push({ type: 'number', value: parseFloat(numStr) });
                } else if (ch === '=') {
                    // Skip the leading = sign
                    i++;
                    continue;
                } else if ((ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z')) {
                    let ref = '';
                    while (i < formula.length && 
                          ((formula[i] >= 'A' && formula[i] <= 'Z') || 
                           (formula[i] >= 'a' && formula[i] <= 'z') ||
                           (formula[i] >= '0' && formula[i] <= '9'))) {
                        ref += formula[i];
                        i++;
                    }

                    // Check if it's a cell reference
                    const match = ref.match(/^([A-Za-z]+)(\d+)$/);
                    if (match) {
                        const colLabel = match[1].toUpperCase();
                        const row = parseInt(match[2]);

                        if (COLS_LABELS.includes(colLabel) && 
                            row >= 1 && row <= ROWS) {
                            tokens.push({ type: 'cell', value: `${colLabel}${row}` });
                        } else {
                            // Invalid cell reference
                            return null;
                        }
                    } else {
                        // Not a valid cell reference, treat as error
                        return null;
                    }
                } else {
                    // Invalid character
                    return null;
                }
            }

            return tokens;
        }

        // Parse expression with precedence: + and - have lower precedence than * and /
        function parseExpression(tokens, pos) {
            let left = parseTerm(tokens, pos);
            let currentPos = left.pos;

            while (currentPos < tokens.length && 
                   (tokens[currentPos].type === 'op') &&
                   (tokens[currentPos].value === '+' || tokens[currentPos].value === '-')) {
                const op = tokens[currentPos].value;
                currentPos++;

                const right = parseTerm(tokens, currentPos);
                currentPos = right.pos;

                if (left.value === '#ERR' || right.value === '#ERR') {
                    left = { pos: currentPos, value: '#ERR' };
                } else if (left.value === '#CYCLE' || right.value === '#CYCLE') {
                    left = { pos: currentPos, value: '#CYCLE' };
                } else {
                    const lVal = isNaN(parseFloat(left.value)) ? 0 : parseFloat(left.value);
                    const rVal = isNaN(parseFloat(right.value)) ? 0 : parseFloat(right.value);

                    if (op === '+') {
                        left = { pos: currentPos, value: lVal + rVal };
                    } else {
                        left = { pos: currentPos, value: lVal - rVal };
                    }
                }
            }

            return left;
        }

        function parseTerm(tokens, pos) {
            let left = parseFactor(tokens, pos);
            let currentPos = left.pos;

            while (currentPos < tokens.length && 
                   (tokens[currentPos].type === 'op') &&
                   (tokens[currentPos].value === '*' || tokens[currentPos].value === '/')) {
                const op = tokens[currentPos].value;
                currentPos++;

                const right = parseFactor(tokens, currentPos);
                currentPos = right.pos;

                if (left.value === '#ERR' || right.value === '#ERR') {
                    left = { pos: currentPos, value: '#ERR' };
                } else if (left.value === '#CYCLE' || right.value === '#CYCLE') {
                    left = { pos: currentPos, value: '#CYCLE' };
                } else {
                    const lVal = isNaN(parseFloat(left.value)) ? 0 : parseFloat(left.value);
                    const rVal = isNaN(parseFloat(right.value)) ? 0 : parseFloat(right.value);

                    if (op === '*') {
                        left = { pos: currentPos, value: lVal * rVal };
                    } else {
                        if (rVal === 0) {
                            left = { pos: currentPos, value: '#ERR' };
                        } else {
                            left = { pos: currentPos, value: lVal / rVal };
                        }
                    }
                }
            }

            return left;
        }

        function parseFactor(tokens, pos) {
            if (pos >= tokens.length) {
                return { pos: pos, value: 0 };
            }

            const token = tokens[pos];

            if (token.type === 'number') {
                return { pos: pos + 1, value: token.value };
            } else if (token.type === 'cell') {
                // Get the computed value of the referenced cell
                const cellValue = computedValues[token.value];

                // If it's a cycle or error, propagate it
                if (cellValue === '#CYCLE' || cellValue === '#ERR') {
                    return { pos: pos + 1, value: cellValue };
                }

                // Check if the referenced cell is being calculated (cycle detection)
                if (cellValue === '#CALCULATING') {
                    return { pos: pos + 1, value: '#CYCLE' };
                }

                // If it's a raw number string
                const num = parseFloat(cellValue);
                if (!isNaN(num)) {
                    return { pos: pos + 1, value: num };
                } else {
                    // Non-numeric text displays as itself (but in formulas we treat empty as 0)
                    return { pos: pos + 1, value: cellValue === '' ? 0 : '#ERR' };
                }
            } else if (token.type === 'op' && token.value === '(') {
                const result = parseExpression(tokens, pos + 1);

                // Check for closing parenthesis
                if (result.pos < tokens.length && 
                    tokens[result.pos].type === 'op' && 
                    tokens[result.pos].value === ')') {
                    return { pos: result.pos + 1, value: result.value };
                } else {
                    return { pos: result.pos, value: '#ERR' };
                }
            } else if (token.type === 'op' && token.value === '-') {
                // Unary minus
                const next = parseFactor(tokens, pos + 1);

                if (next.value === '#ERR' || next.value === '#CYCLE') {
                    return { pos: next.pos, value: next.value };
                }

                const val = isNaN(parseFloat(next.value)) ? 0 : parseFloat(next.value);
                return { pos: next.pos, value: -val };
            } else if (token.type === 'op' && token.value === '+') {
                // Unary plus
                return parseFactor(tokens, pos + 1);
            } else {
                return { pos: pos, value: '#ERR' };
            }
        }

        function evaluateFormula(formula) {
            try {
                // Remove leading = if present
                const cleanFormula = formula.startsWith('=') ? formula.substring(1) : formula;

                // If empty formula after removing =
                if (cleanFormula.trim() === '') {
                    return '';
                }

                const tokens = tokenize(cleanFormula);

                if (!tokens || tokens.length === 0) {
                    return '';
                }

                const result = parseExpression(tokens, 0);

                if (result.pos !== tokens.length) {
                    // Not all tokens consumed - syntax error
                    return '#ERR';
                }

                // Format the result
                if (typeof result.value === 'number') {
                    // Check for special values
                    if (!isFinite(result.value)) {
                        return '#ERR';
                    } else if (isNaN(result.value)) {
                        return '#ERR';
                    } else {
                        // Return as integer if it's a whole number, otherwise with decimals
                        return result.value % 1 === 0 ? result.value.toString() : 
                               parseFloat(result.value.toFixed(6)).toString();
                    }
                } else {
                    return result.value;
                }
            } catch (e) {
                return '#ERR';
            }
        }

        // Recalculate a cell and all cells that depend on it
        function recalculate(cellId, visited = new Set()) {
            if (visited.has(cellId)) return;
            visited.add(cellId);

            const rawValue = rawData[cellId] || '';

            // If the cell contains a formula
            if (rawValue.startsWith('=')) {
                // Mark as calculating to detect cycles
                computedValues[cellId] = '#CALCULATING';

                const result = evaluateFormula(rawValue);

                // Check for cycle detection in dependencies
                if (result === '#CYCLE') {
                    // Propagate cycle to all dependents
                    for (const dep of dependencies[cellId]) {
                        recalculate(dep, visited);
                    }
                    computedValues[cellId] = '#CYCLE';
                } else {
                    computedValues[cellId] = result;

                    // Recalculate dependent cells
                    for (const dep of dependencies[cellId]) {
                        recalculate(dep, visited);
                    }
                }
            } else {
                // Plain value - just update the computed value
                computedValues[cellId] = rawValue;

                // Recalculate dependent cells
                for (const dep of dependencies[cellId]) {
                    recalculate(dep, visited);
                }
            }
        }

        // Update dependencies when a cell's formula changes
        function updateDependencies(cellId) {
            const rawValue = rawData[cellId] || '';

            // Remove this cell from all dependency lists first
            for (const key in dependencies) {
                if (dependencies[key].has(cellId)) {
                    dependencies[key].delete(cellId);
                }
            }

            // If it's a formula, find all cell references and add to their dependency lists
            if (rawValue.startsWith('=')) {
                const cleanFormula = rawValue.substring(1);
                const tokens = tokenize(cleanFormula);

                if (tokens) {
                    for (const token of tokens) {
                        if (token.type === 'cell') {
                            dependencies[token.value].add(cellId);
                        }
                    }
                }
            }
        }

        // Create the grid UI
        function createGrid() {
            const container = document.getElementById('grid-container');

            // Add corner cell
            const cornerCell = document.createElement('div');
            cornerCell.className = 'header';
            container.appendChild(cornerCell);

            // Add column headers (A-J)
            for (let c = 0; c < COLS; c++) {
                const header = document.createElement('div');
                header.className = 'header';
                header.textContent = COLS_LABELS[c];
                container.appendChild(header);
            }

            // Add rows
            for (let r = 1; r <= ROWS; r++) {
                // Row number header
                const rowHeader = document.createElement('div');
                rowHeader.className = 'header';
                rowHeader.textContent = r;
                container.appendChild(rowHeader);

                // Cell inputs
                for (let c = 0; c < COLS; c++) {
                    const cellId = `cell-${COLS_LABELS[c]}${r}`;
                    const input = document.createElement('input');
                    input.type = 'text';
                    input.id = cellId;
                    input.className = 'cell';

                    // Set initial value
                    input.value = '';

                    // Event handlers for editing
                    input.addEventListener('focus', function() {
                        this.dataset.rawValue = rawData[cellId] || '';
                        this.value = rawData[cellId] || '';
                    });

                    input.addEventListener('blur', function() {
                        commitCell(cellId, this.value);
                    });

                    input.addEventListener('keydown', function(e) {
                        if (e.key === 'Enter') {
                            commitCell(cellId, this.value);
                            // Move to next cell
                            const currentRow = r;
                            const currentCol = c;
                            let nextRow = currentRow;
                            let nextCol = currentCol + 1;

                            if (nextCol >= COLS) {
                                nextCol = 0;
                                nextRow++;
                            }

                            if (nextRow <= ROWS) {
                                document.getElementById(`cell-${COLS_LABELS[nextCol]}${nextRow}`).focus();
                            } else {
                                this.blur();
                            }
                        }
                    });

                    container.appendChild(input);
                }
            }
        }

        // Commit a cell's value
        function commitCell(cellId, newValue) {
            const oldRaw = rawData[cellId] || '';

            if (oldRaw !== newValue) {
                rawData[cellId] = newValue;

                // Update dependencies
                updateDependencies(cellId);

                // Recalculate
                recalculate(cellId);

                // Update UI
                document.getElementById(cellId).value = computedValues[cellId];
            }
        }

        // Initialize the spreadsheet
        createGrid();

        // Export CSV functionality
        function exportCSV() {
            let csvContent = '';

            for (let r = 1; r <= ROWS; r++) {
                const rowValues = [];

                for (let c = 0; c < COLS; c++) {
                    const cellId = `cell-${COLS_LABELS[c]}${r}`;
                    let value = computedValues[cellId];

                    // Handle special cases
                    if (value === '#ERR' || value === '#CYCLE') {
                        rowValues.push(value);
                    } else if (typeof value === 'string' && value.includes(',')) {
                        // Escape commas by wrapping in quotes
                        rowValues.push(`"${value}"`);
                    } else {
                        rowValues.push(value);
                    }
                }

                csvContent += rowValues.join(',') + '\n';
            }

            document.getElementById('csv').value = csvContent;
        }

        // Set up the export button
        document.getElementById('export').addEventListener('click', exportCSV);

        // Expose the API
        window.sheet = {
            set: function(cellId, value) {
                if (cellId && typeof cellId === 'string' && 
                    /^cell-[A-J]\d{1,2}$/.test(cellId)) {
                    const input = document.getElementById(cellId);

                    // Set the raw value
                    rawData[cellId] = value;

                    // Update dependencies
                    updateDependencies(cellId);

                    // Recalculate
                    recalculate(cellId);

                    // Update UI
                    if (input) {
                        input.value = computedValues[cellId];
                    }
                } else {
                    console.error('Invalid cell ID');
                }
            },

            get: function(cellId) {
                if (cellId && typeof cellId === 'string' && 
                    /^cell-[A-J]\d{1,2}$/.test(cellId)) {
                    return computedValues[cellId] || '';
                } else {
                    console.error('Invalid cell ID');
                    return '';
                }
            },

            raw: function(cellId) {
                if (cellId && typeof cellId === 'string' && 
                    /^cell-[A-J]\d{1,2}$/.test(cellId)) {
                    return rawData[cellId] || '';
                } else {
                    console.error('Invalid cell ID');
                    return '';
                }
            }
        };
    </script>
</body>
</html>
